module synchronizer(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);

reg [3:0] sync_data_in;
reg [1:0] sync_data_en;

always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        sync_data_in <= 4'b0;
        sync_data_en <= 2'b0;
    end else begin
        sync_data_in <= data_in;
        sync_data_en <= {sync_data_en[0], data_en};
    end
end

always @(posedge clk_b or negedge arstn) begin
    if (!arstn) begin
        dataout <= 4'b0;
    end else if (sync_data_en[1]) begin
        dataout <= sync_data_in;
    end
end

endmodule
